$checkpointPath = ".factory/checkpoints/pre-verification-ready"
if (Test-Path $checkpointPath) {
  Write-Host "Checkpoint already exists (unexpected for first pass):" $checkpointPath
} else {
  New-Item -ItemType Directory -Force -Path (Split-Path $checkpointPath) | Out-Null
  $stamp = Get-Date -Format o
  Set-Content -Path $checkpointPath -Value "pre-verification-ready: $stamp" -Encoding UTF8
  Write-Host "Created checkpoint:" $checkpointPath
}

# Verify it exists
Get-Item $checkpointPath | Format-List FullName,Length,LastWriteTime
